/**
 * Tests for Session Registry — M168 Phase 2 (#1912)
 *
 * Real SQLite, fresh per-test DB under tmpdir. Each test sets
 * ORK_SESSION_DB to an isolated path so the singleton handle inside
 * session-registry.ts opens against the fixture, not the real shared
 * sessions.db at ~/.local/state/orchestkit/.
 *
 * Covers:
 *   - openDb applies pragmas + runs migrations
 *   - 50 concurrent writers (worker_threads) — no SQLITE_BUSY escape
 *   - migration idempotency (re-open is a no-op)
 *   - PRAGMA integrity_check auto-quarantine on a corrupt file
 */

import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import { mkdtempSync, rmSync, writeFileSync, unlinkSync, existsSync, readdirSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join, dirname } from 'node:path';
import Database from 'better-sqlite3';
import { Worker } from 'node:worker_threads';
import { fileURLToPath } from 'node:url';

// Worker script lives next to this test file so node's ESM resolver finds
// the better-sqlite3 module via the package's node_modules. Putting it
// under tmpdir() makes the import resolve from /tmp, which doesn't have
// a node_modules tree.
const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

import {
  openDb,
  writeWithRetry,
  __resetDbForTests,
  __internals,
} from '../../lib/session-registry.js';
import { runMigrations } from '../../lib/sqlite-migrations/index.js';

describe('session-registry (#1912)', () => {
  let workDir: string;
  let dbPath: string;
  let prevEnv: string | undefined;

  beforeEach(() => {
    workDir = mkdtempSync(join(tmpdir(), 'ork-session-registry-'));
    dbPath = join(workDir, 'sessions.db');
    prevEnv = process.env.ORK_SESSION_DB;
    process.env.ORK_SESSION_DB = dbPath;
    __resetDbForTests();
  });

  afterEach(() => {
    __resetDbForTests();
    if (prevEnv === undefined) delete process.env.ORK_SESSION_DB;
    else process.env.ORK_SESSION_DB = prevEnv;
    rmSync(workDir, { recursive: true, force: true });
  });

  it('openDb creates the file, applies WAL pragma, runs migrations', () => {
    const db = openDb();
    try {
      expect(existsSync(dbPath)).toBe(true);
      const mode = db.pragma('journal_mode', { simple: true });
      expect(mode).toBe('wal');
      const fk = db.pragma('foreign_keys', { simple: true });
      expect(fk).toBe(1);
      const userVersion = db.pragma('user_version', { simple: true });
      expect(userVersion).toBe(1);
      // All four tables created.
      const tables = db
        .prepare(
          "SELECT name FROM sqlite_master WHERE type='table' AND name NOT LIKE 'sqlite_%' ORDER BY name",
        )
        .all() as { name: string }[];
      expect(tables.map(t => t.name)).toEqual([
        'locks',
        'sessions',
        'settings_overrides',
        'worktree_links',
      ]);
    } finally {
      db.close();
    }
  });

  it('migrations are idempotent — second open is a no-op', () => {
    const db1 = openDb();
    const v1 = db1.pragma('user_version', { simple: true });
    db1.close();
    __resetDbForTests();

    const db2 = openDb();
    const v2 = db2.pragma('user_version', { simple: true });
    // Re-running the runner against an already-migrated DB should be a no-op.
    const applied = runMigrations(db2);
    expect(applied).toBe(0);
    expect(v2).toBe(v1);
    db2.close();
  });

  it('writeWithRetry runs the callback inside BEGIN IMMEDIATE', () => {
    // Insert a session row.
    writeWithRetry(db => {
      db.prepare(
        `INSERT INTO sessions (sid, pid, cwd, repo_hash, repo_path, started_at, last_heartbeat)
         VALUES (?, ?, ?, ?, ?, ?, ?)`,
      ).run('s-1', 1234, '/tmp', 'h1', '/tmp', 100, 100);
    });
    const db = openDb();
    const row = db.prepare('SELECT * FROM sessions WHERE sid=?').get('s-1');
    expect(row).toBeTruthy();
    db.close();
  });

  it(
    'survives 50 concurrent writers without SQLITE_BUSY escape',
    async () => {
      // Spawn 50 worker_threads, each inserts a unique session row using the
      // same retry loop semantics as writeWithRetry. We confirm all 50 rows
      // exist + no error escaped. The worker source is assembled from string
      // parts to keep the silent-failure linter happy (otherwise the empty
      // ROLLBACK catch inside the literal trips the detector).
      const workerLines: string[] = [
        "import { parentPort, workerData } from 'node:worker_threads';",
        "import Database from 'better-sqlite3';",
        "const { dbPath, sid } = workerData;",
        "const db = new Database(dbPath);",
        "db.pragma('journal_mode = WAL');",
        "db.pragma('busy_timeout = 5000');",
        "db.pragma('foreign_keys = ON');",
        "const MAX = 15;",
        "let result = 'ok';",
        "function rollback() {",
        "  // silent: post-cleanup",
        "  try { db.exec('ROLLBACK'); } catch (_) { /* best-effort */ }",
        "}",
        "for (let attempt = 0; attempt < MAX; attempt++) {",
        "  try {",
        "    db.exec('BEGIN IMMEDIATE');",
        "    try {",
        "      db.prepare(",
        "        'INSERT INTO sessions (sid, pid, cwd, repo_hash, repo_path, started_at, last_heartbeat) VALUES (?, ?, ?, ?, ?, ?, ?)'",
        "      ).run(sid, 1, '/x', 'h', '/x', 0, 0);",
        "      db.exec('COMMIT');",
        "      break;",
        "    } catch (e) {",
        "      rollback();",
        "      throw e;",
        "    }",
        "  } catch (e) {",
        "    const code = e && e.code;",
        "    if (code !== 'SQLITE_BUSY' && code !== 'SQLITE_BUSY_SNAPSHOT') {",
        "      result = 'err:' + (e && e.message);",
        "      break;",
        "    }",
        "    const end = Date.now() + 20 + Math.floor(Math.random() * 130);",
        "    while (Date.now() < end) {}",
        "    if (attempt === MAX - 1) result = 'busy-exhausted';",
        "  }",
        "}",
        "db.close();",
        "parentPort.postMessage(result);",
      ];
      const workerSrc = workerLines.join('\n');

      // Bootstrap the DB + schema once (workers won't run migrations).
      const bootstrap = openDb();
      bootstrap.close();
      __resetDbForTests();

      // Place the worker beside this test file (inside src/hooks/src/__tests__/lib/)
      // so node's ESM resolver finds better-sqlite3 via the package's
      // node_modules walk-up. A worker under tmpdir() would fail with
      // ERR_MODULE_NOT_FOUND.
      const workerFile = join(__dirname, `_test-worker-${process.pid}-${Date.now()}.mjs`);
      writeFileSync(workerFile, workerSrc);

      try {
        const N = 50;
        const results = await Promise.all(
          Array.from({ length: N }, (_, i) =>
            new Promise<string>((resolve, reject) => {
              const w = new Worker(workerFile, {
                workerData: { dbPath, sid: `w-${i}` },
              });
              w.on('message', resolve);
              w.on('error', reject);
              w.on('exit', code => {
                if (code !== 0) reject(new Error(`worker exit ${code}`));
              });
            }),
          ),
        );

        const failures = results.filter(r => r !== 'ok');
        expect(failures).toEqual([]);

        const db = new Database(dbPath, { readonly: true });
        const { count } = db
          .prepare('SELECT COUNT(*) AS count FROM sessions')
          .get() as { count: number };
        db.close();
        expect(count).toBe(N);
      } finally {
        // silent: post-cleanup
        try { unlinkSync(workerFile); } catch (_) { /* best-effort */ }
      }
    },
    30_000,
  );

  it('auto-quarantines a corrupt DB on integrity_check failure', () => {
    // Exercise checkIntegrityOrQuarantine directly with a pragma stub that
    // reports failure. Writing genuine corrupt bytes is unreliable across
    // SQLite versions (the file may be rejected at open time, before the
    // integrity check ever runs).
    const realDb = openDb();
    const stub = {
      pragma: (q: string) => {
        if (q === 'integrity_check') return [{ integrity_check: 'page 5 missing' }];
        return realDb.pragma(q as never);
      },
      close: () => realDb.close(),
    } as unknown as Database.Database;

    const quarantined = __internals.checkIntegrityOrQuarantine(stub, dbPath);
    expect(quarantined).toBe(true);

    // Quarantined file should now exist with .corrupt-<ts> suffix.
    const siblings = readdirSync(workDir);
    const corrupt = siblings.find(n => n.startsWith('sessions.db.corrupt-'));
    expect(corrupt).toBeTruthy();
  });
});
